// Вспомогательная функция для поиска изображения
export const findImageInMap = (path: string): any => {
  if (!path) return IMAGE_MAP.placeholder;
  // console.log('findImageInMap', path);
  // Убираем префиксы
  const cleanPath = path
    .replace(/^assets\//, '')
    .replace(/^Image\/Banknotes\//, '');

  // Ищем полное совпадение
  if (IMAGE_MAP[cleanPath]) {
    return IMAGE_MAP[cleanPath];
  }

  console.warn(`Изображение не найдено: ${path}`);
  return IMAGE_MAP.placeholder;
};

export default IMAGE_MAP;